package main

import (
	"context"
	"fmt"
	"time"

	lua "github.com/yuin/gopher-lua"
)

// ExecutePricingScript executes a user-provided Lua script to calculate the final price
// of a product based on the given context.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a new Lua state with restricted options for security
	L := lua.NewState(lua.Options{
		SkipOpenLibs: true,
	})
	defer L.Close()

	// Open only safe standard libraries
	for _, lib := range []struct {
		name string
		fn   lua.LGFunction
	}{
		{lua.BaseLibName, lua.OpenBase},
		{lua.MathLibName, lua.OpenMath},
		{lua.StringLibName, lua.OpenString},
	} {
		L.Push(L.NewFunction(lib.fn))
		L.Push(lua.LString(lib.name))
		L.Call(1, 0)
	}

	// Disable dangerous functions from base library
	L.SetGlobal("dofile", lua.LNil)
	L.SetGlobal("loadfile", lua.LNil)
	L.SetGlobal("require", lua.LNil)
	L.SetGlobal("load", lua.LNil)
	L.SetGlobal("loadstring", lua.LNil)

	// Set up execution timeout using context
	ctxWithTimeout, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	// Channel to capture result or error
	type result struct {
		val float64
		err error
	}
	done := make(chan result, 1)

	go func() {
		defer func() {
			if r := recover(); r != nil {
				done <- result{0, fmt.Errorf("Lua script panicked: %v", r)}
			}
		}()

		// Load and execute the script
		if err := L.DoString(script); err != nil {
			done <- result{0, fmt.Errorf("failed to execute Lua script: %w", err)}
			return
		}

		// Get the calculate_final_price function from global scope
		fn := L.GetGlobal("calculate_final_price")
		if fn.Type() != lua.LTFunction {
			done <- result{0, fmt.Errorf("calculate_final_price is not a function or not defined")}
			return
		}

		// Convert Go context map to Lua table
		ctxTable := L.NewTable()
		for k, v := range ctx {
			L.SetField(ctxTable, k, lua.LNumber(v))
		}

		// Call the function with the context table
		if err := L.CallByParam(lua.P{
			Fn:      fn,
			NRet:    1,
			Protect: true,
		}, ctxTable); err != nil {
			done <- result{0, fmt.Errorf("failed to call calculate_final_price: %w", err)}
			return
		}

		// Get the result from the Lua stack
		lresult := L.Get(-1)
		L.Pop(1) // Remove the result from the stack

		// Convert result to float64
		if lresult.Type() != lua.LTNumber {
			done <- result{0, fmt.Errorf("calculate_final_price did not return a number")}
			return
		}

		done <- result{float64(lresult.(lua.LNumber)), nil}
	}()

	select {
	case <-ctxWithTimeout.Done():
		return 0, fmt.Errorf("script execution timed out")
	case res := <-done:
		return res.val, res.err
	}
}

